// Learn: Throw a custom exception and catch alternatives together.
class MissingScoreException extends Exception {}

int parseScore(String text) throws MissingScoreException {
  if (text.trim().isEmpty()) throw new MissingScoreException();
  return Integer.parseInt(text);
}

try {
  parseScore(input);
} catch (NumberFormatException | MissingScoreException e) {
  // Multi-catch handles either exception in one block.
  System.out.println(e.getClass().getSimpleName());
}
